from html import escape

# --- Configuração ---
DESC_LIMIT = 500  # Limite de caracteres para a descrição HTML

# --- Funções de Ajuda ---

def ensure_list(name, value):
    """Garante que o valor é uma lista ou um JsProxy convertível para lista."""
    if isinstance(value, list):
        return value
    try:
        # Tenta converter o JsProxy (n8n/js) para uma lista Python
        return value.to_py()
    except Exception as e:
        raise TypeError(f"'{name}' não é lista nem JsProxy convertível: {type(value)}") from e

def to_num(v):
    """Converte um valor (int, float, str, None) para float, tratando formatos de string."""
    if v is None:
        return None
    if isinstance(v, (int, float)):
        return float(v)
    if isinstance(v, str):
        s = v.strip()
        try:
            # Tenta converter string com formato BR (ponto separador de milhar, vírgula decimal)
            s_norm = s.replace('.', '').replace(',', '.')
            return float(s_norm)
        except Exception:
            try:
                # Tenta conversão padrão (se for formato US, por exemplo)
                return float(s)
            except Exception:
                return None
    try:
        # Última tentativa de conversão genérica (pode ser JsProxy de número)
        return float(v)
    except Exception:
        return None

def warn(message: str, ctx: dict, idx: int):
    """Cria um objeto de saída formatado como 'warning' (n8n)."""
    # A saída de 'warn' também é um dicionário com chave "json" (estrutura exigida pelo n8n)
    return {"json": {
        "severity": "warning",
        "message": message,
        "context": ctx,
        "item_index": idx,
    }}

# --- Processamento Principal ---

# Cabeçalho para o n8n:
# Code in Python (Run Once for All Items)
# SAÍDA FINAL (1 lista) — Formatação Compacta (Opção 3), SEM recalcular regras.
# Retorna: [ {"json": ...}, {"json": ...}, ... ] (Formato exigido pelo n8n)

out_items = []  # Lista de dicionários de saída, sempre com chave "json"

for idx, item in enumerate(_input.all()):
    try:
        j = item.json.to_py()
        # Prioriza 'nome_alvo', senão 'nome', senão um padrão
        nome = str(j.get("nome_alvo") or j.get("nome") or "Cliente")

        # Mapeamento de campos e conversão para número
        queda_pp = to_num(j.get("queda_rent_12_meses"))
        r12 = to_num(j.get("rentabilidade_12_meses"))

        if queda_pp is None:
            out_items.append(warn(
                "'queda_rent_12_meses' ausente ou inválido.",
                {"nome": nome}, 
                idx
            ))
            continue

        # Lógica da Opção 3 compacta (sem recalcular a regra)
        if r12 is not None:
            # r_prev é calculado APENAS para exibição na descrição, a regra de negócio não é reavaliada
            r_prev = r12 + queda_pp
            descricao_html = (
                f"<p>O cliente <strong>{escape(nome)}</strong> teve uma "
                f"<strong>queda de {queda_pp:.2f} p.p.</strong> na rentabilidade de 12 meses "
                f"(<strong>{r_prev:.2f}% &rarr; {r12:.2f}%</strong>).</p>"
                "<i>Recomendamos avaliar a carteira e a estratégia de investimento.</i>"
            )
        else:
            # Caso 'rentabilidade_12_meses' esteja ausente/inválido
            descricao_html = (
                f"<p>O cliente <strong>{escape(nome)}</strong> teve uma "
                f"<strong>queda de {queda_pp:.2f} p.p.</strong> na rentabilidade de 12 meses.</p>"
                "<i>Recomendamos avaliar a carteira e a estratégia de investimento.</i>"
            )

        # Checagem de limite da descrição
        if len(descricao_html) > DESC_LIMIT:
            out_items.append(warn(
                f"Descrição excede o limite de {DESC_LIMIT} caracteres.",
                {"nome": nome, "limite": DESC_LIMIT, "len": len(descricao_html)},
                idx
            ))
            continue

        # Extração e validação dos responsáveis (officers/usuarios_responsaveis)
        responsaveis_raw = j.get("officers") or j.get("usuarios_responsaveis") or []
        responsaveis = ensure_list("officers/usuarios_responsaveis", responsaveis_raw)

        if not responsaveis:
            out_items.append(warn(
                "Nenhum 'officer'/'usuarios_responsaveis' encontrado para notificação.", 
                {"nome": nome}, 
                idx
            ))
            continue

        # Criação dos itens de notificação (um por responsável)
        for resp in responsaveis:
            if not isinstance(resp, (int, str)):
                try:
                    resp = resp.to_py()  # Tenta converter JsProxy para int/str
                except Exception:
                    out_items.append(warn(
                        "Responsável inválido (não é int/str ou JsProxy).", 
                        {"nome": nome}, 
                        idx
                    ))
                    continue # Pula este responsável, mas tenta o próximo

            novo = {
                "titulo": "Alerta de Queda de Rentabilidade (≥ 15%)", # Título padronizado e mais formal
                "descricao": descricao_html,                         # Conteúdo HTML (≤ 500)
                "destinatario": 1,                                # ID do Responsável
                "tipo_notificacao": "Queda de rentabilidade",
            }
            out_items.append({
                "json": novo,
                "pairedItem": {"item": idx}, # Associa ao item original
            })

    except Exception as e:
        out_items.append(warn(
            "Erro inesperado durante o processamento do item.", 
            {"error": str(e)}, 
            idx
        ))
        continue # Processa o próximo item se houver um erro

return out_items
